+struct FkParentValidationCache {
+    target_table: String,
+    validated: HashSet<FkParentValidationKey>,
+}
+
+impl FkParentValidationCache {
+    fn new(target_table: &str) -> Self {
+        Self {
+            target_table: target_table.to_ascii_lowercase(),
+            validated: HashSet::new(),
+        }
+    }
+
+    fn can_cache_parent(&self, parent_table: &str) -> bool {
+        !self.target_table.eq_ignore_ascii_case(parent_table)
+    }
+}
+
+#[derive(Clone, PartialEq, Eq, Hash)]
+struct FkParentValidationKey {
+    child_table: String,
+    parent_table: String,
+    parent_columns: Vec<String>,
+    values: Vec<SqliteValueHashable>,
+}
+
+struct FkParentValidationCacheScope<'a> {
+    cache: &'a RefCell<Option<FkParentValidationCache>>,
+    previous: Option<FkParentValidationCache>,
+}
+
+impl Drop for FkParentValidationCacheScope<'_> {
+    fn drop(&mut self) {
+        *self.cache.borrow_mut() = self.previous.take();
+    }
+}
